	public void ChangeView(int view)
	{
		if (((Control)ViewContainer).ChildCount > view)
		{
			((Control)ViewContainer).GetChild(_currentView).Visible = false;
			((Control)ViewContainer).GetChild(view).Visible = true;
			_currentView = view;
		}
	}

